#include <iostream>
#include <string>
#include <vector>
#include <iomanip>

#define MY_PI_VALUE 3.14159

class Shape {
public:
    virtual double calculateArea() {
        return 0;
    }
    virtual ~Shape() {}
};

class Rectangle : public Shape {
private:
    double m_rect_width_val;
    double m_rect_height_val;

public:
    Rectangle(double w, double h) {
        m_rect_width_val = w;
        m_rect_height_val = h;
    }

    double calculateArea() {
        double temp_w_storage = m_rect_width_val;
        double temp_h_storage = m_rect_height_val;
        double calculated_product = temp_w_storage * temp_h_storage;
        return calculated_product;
    }
};

class Circle : public Shape {
private:
    double m_circle_radius_val;

public:
    Circle(double r) {
        m_circle_radius_val = r;
    }

    double calculateArea() {
        double current_radius = m_circle_radius_val;
        double radius_multiplied_by_itself = current_radius * current_radius;
        return MY_PI_VALUE * radius_multiplied_by_itself;
    }
};

int main() {
    std::stringstream ss;
    ss << std::fixed << std::setprecision(2);

    Shape* rect1 = new Rectangle(5, 10);
    Shape* circ1 = new Circle(3);
    Shape* rect2 = new Rectangle(2.5, 4);
    Shape* circ2 = new Circle(1.5);

    ss << "Rectangle (5x10) Area: " << rect1->calculateArea() << std::endl;
    ss << "Circle (radius 3) Area: " << circ1->calculateArea() << std::endl;
    ss << "Rectangle (2.5x4) Area: " << rect2->calculateArea() << std::endl;
    ss << "Circle (radius 1.5) Area: " << circ2->calculateArea() << std::endl;

    delete rect1;
    delete circ1;
    delete rect2;
    delete circ2;

    std::cout << ss.str();
    return 0;
}
